from flask import Flask, request, render_template_string, redirect, url_for, session
from flask_mail import Mail, Message
import secrets
import string
import hashlib
import sqlite3

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key_here'
app.config['MAIL_SERVER'] = 'smtp.gmail.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = 'your_email@gmail.com'
app.config['MAIL_PASSWORD'] = 'your_password'

mail = Mail(app)

# SQLite database connection
conn = sqlite3.connect('users.db')
cursor = conn.cursor()

# Create table if not exists
cursor.execute('''CREATE TABLE IF NOT EXISTS users
                 (email text PRIMARY KEY, password text, mfa_enabled integer)''')

# Commit changes
conn.commit()

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form['email']
    cursor.execute('SELECT * FROM users WHERE email=?', (email,))
    user = cursor.fetchone()
    
    if user:
        mfa_secret = secrets.token_urlsafe(16)
        hashed_password = hashlib.sha256(user[1].encode()).hexdigest()
        
        cursor.execute('UPDATE users SET mfa_enabled=1, mfa_secret=? WHERE email=?',
                       (mfa_secret, email))
        conn.commit()
        
        return 'MFA enabled successfully'
    else:
        return 'User not found', 404

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.form['email']
    cursor.execute('SELECT * FROM users WHERE email=?', (email,))
    user = cursor.fetchone()
    
    if user and user[2] == 1:
        cursor.execute('UPDATE users SET mfa_enabled=0, mfa_secret=null WHERE email=?',
                       (email,))
        conn.commit()
        
        return 'MFA disabled successfully'
    else:
        return 'User not found or MFA is already disabled', 404

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.form['email']
    
    cursor.execute('SELECT * FROM users WHERE email=?', (email,))
    user = cursor.fetchone()
    
    if user:
        mfa_secret = secrets.token_urlsafe(16)
        
        cursor.execute('UPDATE users SET mfa_enabled=0, mfa_secret=? WHERE email=?',
                       (mfa_secret, email))
        conn.commit()
        
        # Send reset link
        msg = Message('Reset MFA Link', sender='your_email@gmail.com', recipients=[email])
        msg.body = f'Click this link to reset your MFA: {url_for("reset_mfa_link", mfa_secret=mfa_secret, _external=True)}'
        mail.send(msg)
        
        return 'MFA reset link sent successfully'
    else:
        return 'User not found', 404

@app.route('/reset-mfa-link/<mfa_secret>', methods=['GET'])
def reset_mfa_link(mfa_secret):
    if session.get('email') == request.args.get('email'):
        cursor.execute('SELECT * FROM users WHERE email=? AND mfa_enabled=0',
                       (session['email'],))
        user = cursor.fetchone()
        
        if user and user[3] == mfa_secret:
            # Disable MFA
            cursor.execute('UPDATE users SET mfa_enabled=0, mfa_secret=null WHERE email=?',
                           (session['email'],))
            conn.commit()
            
            return 'MFA disabled successfully'
    else:
        return 'Invalid link', 401

@app.route('/login', methods=['POST'])
def login():
    email = request.form['email']
    password = request.form['password']
    
    cursor.execute('SELECT * FROM users WHERE email=? AND mfa_enabled=0',
                   (email,))
    user = cursor.fetchone()
    
    if user and hashlib.sha256(password.encode()).hexdigest() == user[1]:
        session['email'] = email
        return 'Logged in successfully'
    elif user:
        return 'Invalid password', 401
    else:
        return 'User not found', 404

